import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { JobProvider } from './context/JobContext';
import Navbar from './components/Navbar';
import Dashboard from './pages/Dashboard';
import AddJob from './pages/AddJob'; 
import JobDetails from './pages/JobDetails';

// Background style with your colors
const backgroundStyle = {
  background: `linear-gradient(135deg, #e6f7f5 0%, #d1e9f2 100%),
              radial-gradient(circle at 30% 40%, rgba(9, 124, 127, 0.15) 0%, transparent 30%),
              radial-gradient(circle at 70% 60%, rgba(50, 103, 132, 0.15) 0%, transparent 40%),
              repeating-linear-gradient(45deg, rgba(9, 124, 127, 0.03) 0px, rgba(9, 124, 127, 0.03) 2px, transparent 2px, transparent 8px)`,
  minHeight: '100vh',
  position: 'relative',
  margin: 0,
  padding: 0
};

function App() {
  return (
    <JobProvider>
      <Router>
        <div style={backgroundStyle}>
          <Navbar />
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/add" element={<AddJob />} />  
            <Route path="/job/:id" element={<JobDetails />} /> 
            <Route path="/edit/:id" element={<JobDetails />} />
          </Routes>
        </div>
      </Router>
    </JobProvider>
  );
}

export default App;
